import{_ as t,o as i,c as s,ae as a}from"./chunks/framework.BIONGpTb.js";const h=JSON.parse('{"title":"Tabs vs editor registry: responsibility split","description":"","frontmatter":{},"headers":[],"relativePath":"internal/tabs-responsibilities.md","filePath":"internal/tabs-responsibilities.md"}'),o={name:"internal/tabs-responsibilities.md"};function n(r,e,d,c,l,p){return i(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="tabs-vs-editor-registry-responsibility-split" tabindex="-1">Tabs vs editor registry: responsibility split <a class="header-anchor" href="#tabs-vs-editor-registry-responsibility-split" aria-label="Permalink to &quot;Tabs vs editor registry: responsibility split&quot;">​</a></h1><p><strong>LyraTabs</strong> owns all tab UI and the app-state side effects that follow from it:</p><ul><li><strong>activePartSignal / activeEditorSignal</strong>: Updated when a tab is shown (wa-tab-show or click in content) or when a tab is closed, so the active part/editor is cleared. Implemented via <code>syncActiveSignalsFromPanel()</code> and <code>clearActiveSignalsIfPartInPanel()</code>. Only the tab container with <code>id === EDITOR_AREA_MAIN</code> sets <code>activeEditorSignal</code> (when the part has <code>isEditor</code>).</li><li><strong>Dirty state</strong>: Each LyraTabs instance subscribes to <code>partDirtySignal</code> and, when the dirty part is inside one of its panels, calls <code>markDirty(name, dirty)</code> so the tab strip shows the dirty indicator. Subscription is cleaned up in <code>disconnectedCallback</code>.</li></ul><p><strong>EditorRegistry</strong> is responsible for editor input handling, opening/loading editors, and file icons. It only uses <code>getEditorArea()</code> to call <code>open()</code> / <code>activate()</code> on the editor area when opening or switching to an editor.</p><p>Tab-shown and tab-closed custom events are not dispatched; add them in tabs.ts when a listener is needed.</p>',5)])])}const g=t(o,[["render",n]]);export{h as __pageData,g as default};
